import sqlite3
from typing import Optional


def get_order(database_path: str, user_id: int, order_id: int) -> Optional[dict]:
    """
    Retrieve order information from a SQLite database.

    Args:
        database_path: Path to the SQLite database file.
        user_id: The ID of the user who owns the order.
        order_id: The ID of the order to retrieve.

    Returns:
        A dictionary containing the order data, or None if not found.
    """
    conn = None
    try:
        conn = sqlite3.connect(database_path)
        conn.row_factory = sqlite3.Row
        cursor = conn.cursor()

        query = "SELECT * FROM orders WHERE user_id = ? AND order_id = ?"
        cursor.execute(query, (user_id, order_id))

        row = cursor.fetchone()

        if row is None:
            return None

        return dict(row)

    except sqlite3.Error as e:
        print(f"Database error: {e}")
        return None

    finally:
        if conn:
            conn.close()